  ROUND(100 * cum_metric / NULLIF(total_metric,0), 2) AS cumulative_ratio,
  CASE WHEN cum_metric / NULLIF(total_metric,0) <= 0.7 THEN 'A'
       WHEN cum_metric / NULLIF(total_metric,0) <= 0.9 THEN 'B' ELSE 'C' END AS abc_class
FROM final
ORDER BY rank
LIMIT 5000


